const e=JSON.parse('{"key":"v-e2c1c630","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/05-%E7%A5%9E%E5%A5%87%E7%9A%84%E5%8D%81%E5%AD%97%E7%BA%BF.html","title":"神奇的十字线","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["十字线"],"order":5,"description":"神奇的十字线 image-20240124004802531 正如第三章所介绍，十字线是一类特别的蜡烛线，其开市价与收市价处在同一个水平上。从图8.1到图8.3显示的是十字蜡烛线的各种例子。因为十字线是一种极其重要的反转信号，所以我们专门辟出这一章来对其进行研究。在过去的各章中，我们已经看到十字线作为一些蜡烛线形态的组成部分所发挥的重要力量。这类形态包括十字星形态（参见第五章），以及十字孕线形态（参见第六章）。 十字线的重要性 在一根完美的十字线上，开市价与收市价处于同一水平，不过，这一标准也有一定程度的灵活性。如果某根蜡烛线的开市价与收市价仅仅有很少几个基本价格单位的差别（举例来讲，在谷物市场上其差别仅为1/4美分，或者在长期国债市场上仅有几个1/32美元的差距，等等），那么，依然可以把这条蜡烛线看成一根十字线。根据什么原则来认定，一根近似于十字线的蜡烛线（这就是说，它的开市价与收市价很接近，但不是严格一致）到底算不算一根十字线呢？这是一个带有主观色彩的问题，找不到严格的标准答案。不过，有一个补救办法，就看这根近似的十字线与其邻近的价格变化的相互关系是怎么样的。如果在这根近似的十字线的周围，还有一系列的小实体，那么，就不应该认为这根蜡烛线有多大的意义，因为在它附近有这么多的小实体蜡烛线。还有一种补救技巧，是基于这根蜡烛线所处的市场形势来考虑。如果当时市场正处在一个重要的转折点，或者正处在牛市或熊市的晚期阶段，或者当时已经有其它技术信号发出了警告信息，那么，此时出现的近似十字线就应当看成一根十字线。这种做法的理论依据是，因为十字线可能构成了重要的警告信号，所以我们宁可错认，也不能漏过；遇上一个虚假的警告信号，总比漏过一个真正的危险信号强得多。由于十字线蕴含眷多方面的技术意义，忽略一根十字线，就可能招致危险。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/05-%E7%A5%9E%E5%A5%87%E7%9A%84%E5%8D%81%E5%AD%97%E7%BA%BF.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"神奇的十字线"}],["meta",{"property":"og:description","content":"神奇的十字线 image-20240124004802531 正如第三章所介绍，十字线是一类特别的蜡烛线，其开市价与收市价处在同一个水平上。从图8.1到图8.3显示的是十字蜡烛线的各种例子。因为十字线是一种极其重要的反转信号，所以我们专门辟出这一章来对其进行研究。在过去的各章中，我们已经看到十字线作为一些蜡烛线形态的组成部分所发挥的重要力量。这类形态包括十字星形态（参见第五章），以及十字孕线形态（参见第六章）。 十字线的重要性 在一根完美的十字线上，开市价与收市价处于同一水平，不过，这一标准也有一定程度的灵活性。如果某根蜡烛线的开市价与收市价仅仅有很少几个基本价格单位的差别（举例来讲，在谷物市场上其差别仅为1/4美分，或者在长期国债市场上仅有几个1/32美元的差距，等等），那么，依然可以把这条蜡烛线看成一根十字线。根据什么原则来认定，一根近似于十字线的蜡烛线（这就是说，它的开市价与收市价很接近，但不是严格一致）到底算不算一根十字线呢？这是一个带有主观色彩的问题，找不到严格的标准答案。不过，有一个补救办法，就看这根近似的十字线与其邻近的价格变化的相互关系是怎么样的。如果在这根近似的十字线的周围，还有一系列的小实体，那么，就不应该认为这根蜡烛线有多大的意义，因为在它附近有这么多的小实体蜡烛线。还有一种补救技巧，是基于这根蜡烛线所处的市场形势来考虑。如果当时市场正处在一个重要的转折点，或者正处在牛市或熊市的晚期阶段，或者当时已经有其它技术信号发出了警告信息，那么，此时出现的近似十字线就应当看成一根十字线。这种做法的理论依据是，因为十字线可能构成了重要的警告信号，所以我们宁可错认，也不能漏过；遇上一个虚假的警告信号，总比漏过一个真正的危险信号强得多。由于十字线蕴含眷多方面的技术意义，忽略一根十字线，就可能招致危险。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-01-25T16:48:36.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"十字线"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-01-25T16:48:36.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"神奇的十字线\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-01-25T16:48:36.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"十字线的重要性","slug":"十字线的重要性","link":"#十字线的重要性","children":[]},{"level":2,"title":"市场顶部的十字线","slug":"市场顶部的十字线","link":"#市场顶部的十字线","children":[]},{"level":2,"title":"出现在长长的白色蜡烛线之后的十字线","slug":"出现在长长的白色蜡烛线之后的十字线","link":"#出现在长长的白色蜡烛线之后的十字线","children":[]},{"level":2,"title":"长腿十字线和黄包车夫","slug":"长腿十字线和黄包车夫","link":"#长腿十字线和黄包车夫","children":[]},{"level":2,"title":"墓碑十字线","slug":"墓碑十字线","link":"#墓碑十字线","children":[]},{"level":2,"title":"构成支撑水平和阻挡水平的十字线","slug":"构成支撑水平和阻挡水平的十字线","link":"#构成支撑水平和阻挡水平的十字线","children":[]},{"level":2,"title":"三星形态","slug":"三星形态","link":"#三星形态","children":[]},{"level":2,"title":"蜡烛图技术汇总","slug":"蜡烛图技术汇总","link":"#蜡烛图技术汇总","children":[]}],"git":{"createdTime":1706028721000,"updatedTime":1706201316000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":2}]},"readingTime":{"minutes":27.11,"words":8133},"filePathRelative":"证券交易/日本蜡烛图技术/05-神奇的十字线.md","localizedDate":"2024年1月17日","excerpt":"<h1> 神奇的十字线</h1>\\n<figure><figcaption>image-20240124004802531</figcaption></figure>\\n<p>正如第三章所介绍，十字线是一类特别的蜡烛线，其开市价与收市价处在同一个水平上。从图8.1到图8.3显示的是十字蜡烛线的各种例子。因为十字线是一种极其重要的反转信号，所以我们专门辟出这一章来对其进行研究。在过去的各章中，我们已经看到十字线作为一些蜡烛线形态的组成部分所发挥的重要力量。这类形态包括十字星形态（参见第五章），以及十字孕线形态（参见第六章）。</p>\\n<h2> 十字线的重要性</h2>\\n<p>在一根完美的十字线上，开市价与收市价处于同一水平，不过，这一标准也有一定程度的灵活性。如果某根蜡烛线的开市价与收市价仅仅有很少几个基本价格单位的差别（举例来讲，在谷物市场上其差别仅为1/4美分，或者在长期国债市场上仅有几个1/32美元的差距，等等），那么，依然可以把这条蜡烛线看成一根十字线。根据什么原则来认定，一根近似于十字线的蜡烛线（这就是说，它的开市价与收市价很接近，但不是严格一致）到底算不算一根十字线呢？这是一个带有主观色彩的问题，找不到严格的标准答案。不过，有一个补救办法，就看这根近似的十字线与其邻近的价格变化的相互关系是怎么样的。如果在这根近似的十字线的周围，还有一系列的小实体，那么，就不应该认为这根蜡烛线有多大的意义，因为在它附近有这么多的小实体蜡烛线。还有一种补救技巧，是基于这根蜡烛线所处的市场形势来考虑。如果当时市场正处在一个重要的转折点，或者正处在牛市或熊市的晚期阶段，或者当时已经有其它技术信号发出了警告信息，那么，此时出现的近似十字线就应当看成一根十字线。这种做法的理论依据是，因为十字线可能构成了重要的警告信号，所以我们宁可错认，也不能漏过；遇上一个虚假的警告信号，总比漏过一个真正的危险信号强得多。由于十字线蕴含眷多方面的技术意义，忽略一根十字线，就可能招致危险。</p>","autoDesc":true}');export{e as data};
